package com.shanfuchun.courtassistant.ui

import android.content.Intent
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.appcompat.app.AlertDialog
import androidx.core.content.FileProvider
import androidx.fragment.app.Fragment
import androidx.fragment.app.activityViewModels
import androidx.recyclerview.widget.LinearLayoutManager
import com.shanfuchun.courtassistant.R
import com.shanfuchun.courtassistant.databinding.FragmentDocsBinding
import java.io.File
import java.io.FileOutputStream
import java.util.zip.ZipEntry
import java.util.zip.ZipOutputStream

class DocsFragment : Fragment() {
    private var _b: FragmentDocsBinding? = null
    private val b get() = _b!!
    private val vm: MainViewModel by activityViewModels()

    override fun onCreateView(i: LayoutInflater, c: ViewGroup?, s: Bundle?): View {
        _b = FragmentDocsBinding.inflate(i, c, false)
        return b.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        val menuAdapter = SmsMenuAdapter { smsId -> vm.selectSms(smsId) }
        b.rvMenu.layoutManager = LinearLayoutManager(requireContext(), LinearLayoutManager.HORIZONTAL, false)
        b.rvMenu.adapter = menuAdapter

        val docAdapter = DocAdapter(
            onShare = { doc -> if (doc.filePath.isNotEmpty()) shareFile(doc.filePath, doc.fileName) },
            onSelect = { updateActionBar() },
            onClick = { doc ->
                if (doc.parseStatus == 4 && doc.sourceUrl.isNotEmpty()) {
                    val intent = Intent(requireContext(), WebViewActivity::class.java).apply {
                        putExtra("url", doc.sourceUrl)
                        putExtra("smsId", doc.smsId)
                        putExtra("docId", doc.id)
                    }
                    startActivity(intent)
                } else if (doc.filePath.isNotEmpty()) {
                    previewPdf(doc.filePath)
                }
            }
        )
        b.rvDocs.layoutManager = LinearLayoutManager(requireContext())
        b.rvDocs.adapter = docAdapter

        vm.smsList.observe(viewLifecycleOwner) { list ->
            menuAdapter.submitList(list)
        }

        vm.calendarSyncMap.observe(viewLifecycleOwner) { map ->
            menuAdapter.updateCalendarSync(map)
        }

        vm.currentDocs.observe(viewLifecycleOwner) { list ->
            docAdapter.submitList(list)
            b.tvEmpty.visibility = if (list.isEmpty()) View.VISIBLE else View.GONE
        }

        // 初始加载日历同步状态
        vm.refreshCalendarSyncMap()

        b.btnDelete.setOnClickListener {
            val selected = (b.rvDocs.adapter as DocAdapter).getSelectedIds()
            if (selected.isEmpty()) { Toast.makeText(requireContext(), "请先选择文档", Toast.LENGTH_SHORT).show(); return@setOnClickListener }
            AlertDialog.Builder(requireContext())
                .setTitle("删除文档")
                .setItems(arrayOf("仅删除记录", "删除记录和文件")) { _, which ->
                    vm.deleteDocs(selected, deleteFiles = which == 1)
                    (b.rvDocs.adapter as DocAdapter).clearSelection()
                    updateActionBar()
                }.show()
        }

        b.btnSelectAll.setOnClickListener {
            (b.rvDocs.adapter as DocAdapter).toggleSelectAll()
            updateActionBar()
        }

        b.btnShareBatch.setOnClickListener {
            val selected = (b.rvDocs.adapter as DocAdapter).getSelectedIds()
            if (selected.isEmpty()) { Toast.makeText(requireContext(), "请先选择文档", Toast.LENGTH_SHORT).show(); return@setOnClickListener }
            vm.getDocsByIds(selected) { docs ->
                val files = docs.mapNotNull { d -> File(d.filePath).takeIf { it.exists() } }
                if (files.isEmpty()) { Toast.makeText(requireContext(), "所选文件不存在", Toast.LENGTH_SHORT).show(); return@getDocsByIds }
                if (files.size == 1) {
                    shareFile(files[0].absolutePath, files[0].name)
                } else {
                    shareAsZip(files)
                }
            }
        }
    }

    private fun updateActionBar() {
        val count = (b.rvDocs.adapter as DocAdapter).getSelectedIds().size
        b.btnDelete.visibility = if (count > 0) View.VISIBLE else View.GONE
        b.btnShareBatch.visibility = if (count > 0) View.VISIBLE else View.GONE
        b.tvSelected.text = if (count > 0) "已选 $count 项" else ""
    }

    private fun shareFile(path: String, name: String) {
        try {
            val file = File(path)
            if (!file.exists()) { Toast.makeText(requireContext(), "文件不存在", Toast.LENGTH_SHORT).show(); return }
            val uri = FileProvider.getUriForFile(requireContext(), "${requireContext().packageName}.fileprovider", file)
            val intent = Intent(Intent.ACTION_SEND).apply {
                type = "application/pdf"
                putExtra(Intent.EXTRA_STREAM, uri)
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            startActivity(Intent.createChooser(intent, "分享 $name"))
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "分享失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }

    private fun shareAsZip(files: List<File>) {
        try {
            val zipFile = File(requireContext().cacheDir, "court_docs_${System.currentTimeMillis()}.zip")
            ZipOutputStream(FileOutputStream(zipFile)).use { zos ->
                for (f in files) {
                    zos.putNextEntry(ZipEntry(f.name))
                    f.inputStream().use { it.copyTo(zos) }
                    zos.closeEntry()
                }
            }
            val uri = FileProvider.getUriForFile(requireContext(), "${requireContext().packageName}.fileprovider", zipFile)
            val intent = Intent(Intent.ACTION_SEND).apply {
                type = "application/zip"
                putExtra(Intent.EXTRA_STREAM, uri)
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            startActivity(Intent.createChooser(intent, "分享 ${files.size} 个文件"))
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "打包失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }

    private fun previewPdf(path: String) {
        try {
            val file = File(path)
            if (!file.exists()) { Toast.makeText(requireContext(), "文件不存在", Toast.LENGTH_SHORT).show(); return }
            val uri = FileProvider.getUriForFile(requireContext(), "${requireContext().packageName}.fileprovider", file)
            val intent = Intent(Intent.ACTION_VIEW).apply {
                setDataAndType(uri, "application/pdf")
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            }
            startActivity(intent)
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "无法打开PDF，请安装PDF阅读器", Toast.LENGTH_SHORT).show()
        }
    }

    override fun onDestroyView() { super.onDestroyView(); _b = null }
}

