package com.shanfuchun.courtassistant.ui

import android.graphics.Color
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.DiffUtil
import androidx.recyclerview.widget.ListAdapter
import androidx.recyclerview.widget.RecyclerView
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.databinding.ItemDocBinding
import java.text.SimpleDateFormat
import java.util.*

class DocAdapter(
    private val onShare: (DocumentRecord) -> Unit,
    private val onSelect: () -> Unit,
    private val onClick: (DocumentRecord) -> Unit = {}
) : ListAdapter<DocumentRecord, DocAdapter.VH>(DIFF) {

    private val selected = mutableSetOf<Long>()

    companion object {
        val DIFF = object : DiffUtil.ItemCallback<DocumentRecord>() {
            override fun areItemsTheSame(a: DocumentRecord, b: DocumentRecord) = a.id == b.id
            override fun areContentsTheSame(a: DocumentRecord, b: DocumentRecord) = a == b
        }
        val FMT = SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.CHINA)
    }

    class VH(val b: ItemDocBinding) : RecyclerView.ViewHolder(b.root)

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
        VH(ItemDocBinding.inflate(LayoutInflater.from(parent.context), parent, false))

    override fun onBindViewHolder(h: VH, pos: Int) {
        val item = getItem(pos)
        // 显示 displayName（原网页名称），fallback 到 fileName
        h.b.tvFileName.text = item.displayName.ifEmpty { item.fileName }
        h.b.tvDownloadTime.text = FMT.format(Date(item.downloadTime))
        h.b.tvParseStatus.text = when (item.parseStatus) {
            0 -> "待识别"; 1 -> "已识别"; 2 -> "识别失败"; 3 -> "非传票"; 4 -> "点击下载"; else -> "待识别"
        }
        // 日历同步状态 - 醒目显示
        if (item.calendarSynced) {
            h.b.tvCalendar.text = "✓ 已同步日历"
            h.b.tvCalendar.setTextColor(Color.parseColor("#2E7D32"))
        } else if (item.parseStatus == 1) {
            h.b.tvCalendar.text = "✗ 未同步日历"
            h.b.tvCalendar.setTextColor(Color.parseColor("#9E9E9E"))
        } else {
            h.b.tvCalendar.text = ""
        }
        h.b.cbSelect.isChecked = selected.contains(item.id)
        h.b.cbSelect.setOnCheckedChangeListener { _, checked ->
            if (checked) selected.add(item.id) else selected.remove(item.id)
            onSelect()
        }
        h.b.btnShare.setOnClickListener { onShare(item) }
        h.b.root.setOnClickListener { onClick(item) }
    }

    fun getSelectedIds(): List<Long> = selected.toList()
    fun clearSelection() { selected.clear(); notifyDataSetChanged() }
    fun toggleSelectAll() {
        if (selected.size == currentList.size) selected.clear()
        else { selected.clear(); currentList.forEach { selected.add(it.id) } }
        notifyDataSetChanged()
    }
}

package com.shanfuchun.courtassistant.data

import androidx.lifecycle.LiveData
import androidx.room.*

@Dao
interface SmsDao {
    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    fun getAll(): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    suspend fun getAllSync(): List<SmsRecord>

    @Query("SELECT * FROM sms_record WHERE body LIKE '%' || :q || '%' OR sender LIKE '%' || :q || '%' ORDER BY receiveTime DESC")
    fun search(q: String): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record WHERE id = :id")
    suspend fun getById(id: Long): SmsRecord?

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insert(record: SmsRecord): Long

    @Update
    suspend fun update(record: SmsRecord)

    @Query("SELECT MAX(receiveTime) FROM sms_record")
    suspend fun getLatestTime(): Long?
}

@Dao
interface DocumentDao {
    @Query("SELECT * FROM document_record WHERE smsId = :smsId ORDER BY downloadTime DESC")
    fun getBySmsId(smsId: Long): LiveData<List<DocumentRecord>>

    @Query("SELECT * FROM document_record ORDER BY downloadTime DESC")
    fun getAll(): LiveData<List<DocumentRecord>>

    @Query("SELECT * FROM document_record WHERE id = :id")
    suspend fun getById(id: Long): DocumentRecord?

    @Query("SELECT * FROM document_record WHERE smsId = :smsId")
    suspend fun getBySmsIdSync(smsId: Long): List<DocumentRecord>

    @Query("SELECT * FROM document_record WHERE sourceUrl = :url AND smsId = :smsId LIMIT 1")
    suspend fun findByUrlAndSms(url: String, smsId: Long): DocumentRecord?

    @Query("SELECT * FROM document_record WHERE sourceUrl = :url AND smsId = :smsId AND parseStatus != 4 AND filePath != '' LIMIT 1")
    suspend fun findDownloadedByUrlAndSms(url: String, smsId: Long): DocumentRecord?

    @Query("SELECT COUNT(*) FROM document_record WHERE smsId = :smsId AND calendarSynced = 1")
    suspend fun calendarSyncedCount(smsId: Long): Int

    @Insert
    suspend fun insert(record: DocumentRecord): Long

    @Update
    suspend fun update(record: DocumentRecord)

    @Delete
    suspend fun delete(record: DocumentRecord)

    @Query("DELETE FROM document_record WHERE id IN (:ids)")
    suspend fun deleteByIds(ids: List<Long>)
}

@Dao
interface SummonsDao {
    @Query("SELECT * FROM summons_info WHERE documentId = :docId")
    suspend fun getByDocId(docId: Long): SummonsInfo?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(info: SummonsInfo): Long

    @Query("SELECT * FROM summons_info WHERE hearingTime > 0")
    suspend fun getAllWithHearing(): List<SummonsInfo>
}

@Dao
interface CalendarSyncDao {
    @Query("SELECT * FROM calendar_sync_record WHERE dedupKey = :key LIMIT 1")
    suspend fun findByDedupKey(key: String): CalendarSyncRecord?

    @Insert
    suspend fun insert(record: CalendarSyncRecord): Long

    @Update
    suspend fun update(record: CalendarSyncRecord)
}

