package com.shanfuchun.courtassistant.ui

import android.app.Application
import android.util.Log
import androidx.lifecycle.*
import com.shanfuchun.courtassistant.App
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.service.SmsReader
import com.shanfuchun.courtassistant.service.TextParser
import com.shanfuchun.courtassistant.sms.SmsProcessor
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

class MainViewModel(app: Application) : AndroidViewModel(app) {
    private val db = (app as App).db
    private val TAG = "CourtAssistant"

    val smsList: LiveData<List<SmsRecord>> = db.smsDao().getAll()
    val allDocs: LiveData<List<DocumentRecord>> = db.documentDao().getAll()

    private val _syncStatus = MutableLiveData<String>()
    val syncStatus: LiveData<String> = _syncStatus

    private val _selectedSmsId = MutableLiveData<Long>(0L)
    val selectedSmsId: LiveData<Long> = _selectedSmsId

    // 菜单日历同步状态 map: smsId -> hasCalendarSynced
    private val _calendarSyncMap = MutableLiveData<Map<Long, Boolean>>(emptyMap())
    val calendarSyncMap: LiveData<Map<Long, Boolean>> = _calendarSyncMap

    val currentDocs: LiveData<List<DocumentRecord>> = _selectedSmsId.switchMap { smsId ->
        if (smsId <= 0) db.documentDao().getAll()
        else db.documentDao().getBySmsId(smsId)
    }

    fun selectSms(id: Long) { _selectedSmsId.value = id }

    fun syncSms() {
        viewModelScope.launch {
            _syncStatus.value = "同步中..."
            try {
                val count = withContext(Dispatchers.IO) {
                    val latestTime = db.smsDao().getLatestTime() ?: 0
                    Log.d(TAG, "syncSms: latestTime=$latestTime")
                    val records = SmsReader.readAll(getApplication<App>().contentResolver, latestTime)
                    Log.d(TAG, "syncSms: found ${records.size} records from 12368")
                    var c = 0
                    for (r in records) {
                        Log.d(TAG, "syncSms: processing sms body=${r.body.take(80)} hasLink=${r.hasLink}")
                        val urls = TextParser.extractUrls(r.body)
                        Log.d(TAG, "syncSms: extracted ${urls.size} urls: $urls")
                        val id = db.smsDao().insert(r)
                        if (id > 0) {
                            c++
                            SmsProcessor.process(getApplication(), db, r.copy(id = id))
                        }
                    }
                    c
                }
                _syncStatus.value = if (count > 0) "同步完成，新增 $count 条" else "无新短信"
                _selectedSmsId.value = _selectedSmsId.value
                refreshCalendarSyncMap()
            } catch (e: Exception) {
                Log.e(TAG, "syncSms error", e)
                _syncStatus.value = "同步失败: ${e.message}"
            }
        }
    }

    fun refreshCalendarSyncMap() {
        viewModelScope.launch(Dispatchers.IO) {
            val smsList = db.smsDao().getAllSync()
            val map = mutableMapOf<Long, Boolean>()
            for (sms in smsList) {
                map[sms.id] = db.documentDao().calendarSyncedCount(sms.id) > 0
            }
            _calendarSyncMap.postValue(map)
        }
    }

    fun deleteDocs(ids: List<Long>, deleteFiles: Boolean) {
        viewModelScope.launch(Dispatchers.IO) {
            if (deleteFiles) {
                for (id in ids) {
                    val doc = db.documentDao().getById(id)
                    doc?.let { java.io.File(it.filePath).delete() }
                }
            }
            db.documentDao().deleteByIds(ids)
        }
    }

    fun getDocsByIds(ids: List<Long>, callback: (List<DocumentRecord>) -> Unit) {
        viewModelScope.launch(Dispatchers.IO) {
            val docs = ids.mapNotNull { db.documentDao().getById(it) }
            withContext(Dispatchers.Main) { callback(docs) }
        }
    }

    fun searchSms(query: String): LiveData<List<SmsRecord>> = db.smsDao().search(query)
}

package com.shanfuchun.courtassistant.ui

import android.graphics.Color
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.databinding.ItemSmsMenuBinding
import java.text.SimpleDateFormat
import java.util.*

class SmsMenuAdapter(private val onClick: (Long) -> Unit) :
    RecyclerView.Adapter<SmsMenuAdapter.VH>() {

    private var items: List<SmsRecord> = emptyList()
    private var calendarSyncMap: Map<Long, Boolean> = emptyMap()
    private var selectedPos = 0

    companion object {
        val FMT = SimpleDateFormat("MM-dd HH:mm", Locale.CHINA)
    }

    class VH(val b: ItemSmsMenuBinding) : RecyclerView.ViewHolder(b.root)

    fun submitList(list: List<SmsRecord>) {
        items = list
        notifyDataSetChanged()
    }

    fun updateCalendarSync(map: Map<Long, Boolean>) {
        calendarSyncMap = map
        notifyDataSetChanged()
    }

    override fun getItemCount() = items.size + 1

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
        VH(ItemSmsMenuBinding.inflate(LayoutInflater.from(parent.context), parent, false))

    override fun onBindViewHolder(h: VH, pos: Int) {
        if (pos == 0) {
            h.b.tvLabel.text = "全部"
            h.b.tvInfo.text = ""
            h.b.tvSummonsTag.visibility = View.GONE
            h.b.tvCalendarStatus.visibility = View.GONE
            (h.b.root as? com.google.android.material.card.MaterialCardView)?.setCardBackgroundColor(
                Color.parseColor("#FFF5F0E8")
            )
        } else {
            val sms = items[pos - 1]
            h.b.tvLabel.text = FMT.format(Date(sms.receiveTime))

            // 区分性信息：当事人/法院
            val info = when {
                sms.partyName.isNotEmpty() && sms.courtName.isNotEmpty() ->
                    "${sms.partyName} · ${sms.courtName}"
                sms.partyName.isNotEmpty() -> sms.partyName
                sms.courtName.isNotEmpty() -> sms.courtName
                else -> ""
            }
            h.b.tvInfo.text = info

            // 传票醒目标记
            if (sms.hasSummons) {
                h.b.tvSummonsTag.visibility = View.VISIBLE
                (h.b.root as? com.google.android.material.card.MaterialCardView)?.setCardBackgroundColor(
                    Color.parseColor("#FFF3E0")
                )
            } else {
                h.b.tvSummonsTag.visibility = View.GONE
                (h.b.root as? com.google.android.material.card.MaterialCardView)?.setCardBackgroundColor(
                    Color.parseColor("#FFF5F0E8")
                )
            }

            // 日历同步状态
            val synced = calendarSyncMap[sms.id] == true
            if (synced) {
                h.b.tvCalendarStatus.visibility = View.VISIBLE
                h.b.tvCalendarStatus.text = "✓日历"
                h.b.tvCalendarStatus.setTextColor(Color.parseColor("#2E7D32"))
            } else {
                h.b.tvCalendarStatus.visibility = View.GONE
            }
        }

        h.b.root.isSelected = pos == selectedPos
        h.b.root.setOnClickListener {
            val old = selectedPos
            selectedPos = h.bindingAdapterPosition
            if (old >= 0) notifyItemChanged(old)
            notifyItemChanged(selectedPos)
            onClick(if (pos == 0) 0L else items[pos - 1].id)
        }
    }
}

package com.shanfuchun.courtassistant.sms

import android.content.Context
import android.util.Log
import com.shanfuchun.courtassistant.data.AppDatabase
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.service.CalendarHelper
import com.shanfuchun.courtassistant.service.PdfDownloader
import com.shanfuchun.courtassistant.service.TextParser

object SmsProcessor {
    private const val TAG = "CourtAssistant"

    suspend fun process(context: Context, db: AppDatabase, sms: SmsRecord) {
        Log.d(TAG, "SmsProcessor: processing sms id=${sms.id}")
        val info = TextParser.parse(sms.body)
        Log.d(TAG, "SmsProcessor: parsed info: time=${info.hearingTime} court=${info.courtName} case=${info.caseNo}")

        // 回写 courtName/partyName 到短信记录
        if (info.courtName.isNotEmpty() || info.partyName.isNotEmpty()) {
            db.smsDao().update(sms.copy(courtName = info.courtName, partyName = info.partyName))
        }

        if (info.hearingTime > 0) {
            val synced = CalendarHelper.syncHearing(context, db, info, sms.id, "sms", sms.body)
            Log.d(TAG, "SmsProcessor: calendar synced=$synced")
        }
        val urls = TextParser.extractUrls(sms.body)
        Log.d(TAG, "SmsProcessor: found ${urls.size} urls: $urls")
        if (urls.isNotEmpty()) {
            PdfDownloader.downloadFromUrls(context, db, sms.id, urls)
        }
        // 重新读取，避免覆盖 PdfParser 设置的 hasSummons
        val updated = db.smsDao().getById(sms.id) ?: sms
        db.smsDao().update(updated.copy(
            parseStatus = 1,
            courtName = info.courtName.ifEmpty { updated.courtName },
            partyName = info.partyName.ifEmpty { updated.partyName }
        ))
    }
}

