    73→                    synchronized(allLinksCollected) {
    74→                        if (!downloadedUrls.contains(reqUrl)) {
    75→                            allLinksCollected.add(reqUrl to "")
    76→                        }
    77→                    }
    78→                    return true
    79→                }
    80→                return false
    81→            }
    82→
    83→            override fun onPageFinished(view: WebView, url: String) {
    84→                Log.d(TAG, "WebView page loaded: $url")
    85→                // 第一次扫描
    86→                scanForPdfLinks(view)
    87→                // SPA 延迟重扫 + 点击下载按钮
    88→                view.postDelayed({
    89→                    // 点击所有下载/查看按钮
    90→                    view.evaluateJavascript("""
    91→                        (function() {
    92→                            var btns = document.querySelectorAll('button, .btn, [class*=download], [class*=btn], a');
    93→                            for (var i = 0; i < btns.length; i++) {
    94→                                var t = btns[i].innerText || '';
    95→                                if (t.indexOf('下载') >= 0 || t.indexOf('查看') >= 0) {
    96→                                    btns[i].click();
    97→                                }
    98→                            }
    99→                        })()
   100→                    """.trimIndent(), null)
