                            && allLinksCollected.none { it.first == pdfUrl }) {
                            allLinksCollected.add(pdfUrl to name)
                        }
                    }
                }
                Log.d(TAG, "WebView scan: total ${allLinksCollected.size} links found")
            } catch (e: Exception) {
                Log.e(TAG, "WebView scan parse error", e)
            }
        }
    }

    inner class JsBridge {
        @JavascriptInterface
        fun onPdfLinksFound(json: String) {
            // 保留兼容，但主要靠 scanForPdfLinks
            Log.d(TAG, "WebView JsBridge: $json")
        }
    }

    private fun startBatchDownload() {
        val links: List<Pair<String, String>>
        synchronized(allLinksCollected) {
            links = allLinksCollected.toList()
        }
        if (links.isEmpty()) {
            Toast.makeText(this, "未发现PDF文档", Toast.LENGTH_SHORT).show()
            finish()
            return
        }
        Log.d(TAG, "WebView: starting batch download of ${links.size} files")
        Toast.makeText(this, "发现 ${links.size} 个文档，开始下载...", Toast.LENGTH_SHORT).show()

        scope.launch(Dispatchers.IO) {
            var firstDocHandled = false
            var downloaded = 0
            val totalExpected = links.size
            for ((url, name) in links) {
                if (downloadedUrls.contains(url)) continue
                downloadedUrls.add(url)
                try {
                    val result = downloadOnePdf(url, name, !firstDocHandled)
                    if (result) {
                        firstDocHandled = true
                        downloaded++
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "WebView batch download error: $url", e)
                }
            }

            // 监督机制：对比实际下载数量与源网页数量
            val db = (application as App).db
            val actualDocs = db.documentDao().getBySmsIdSync(smsId)
            val downloadedDocs = actualDocs.filter { it.parseStatus != 4 && it.filePath.isNotEmpty() }
            Log.d(TAG, "WebView: expected=$totalExpected downloaded=$downloaded actual=${downloadedDocs.size}")

            if (downloadedDocs.size < totalExpected) {
                // 未下载完全，保留/更新待下载记录以便用户重试
                val pendingExists = actualDocs.any { it.parseStatus == 4 }
                if (!pendingExists) {
                    val sourceUrl = intent.getStringExtra("url") ?: ""
                    if (sourceUrl.isNotEmpty()) {
                        db.documentDao().insert(
                            DocumentRecord(
                                smsId = smsId, fileName = "未下载完全(${downloadedDocs.size}/$totalExpected) 点击重试",
                                filePath = "", fileSize = 0, sourceUrl = sourceUrl,
                                downloadTime = System.currentTimeMillis(), parseStatus = 4
                            )
                        )
                    }
                }
            } else {
                // 全部下载完成，删除残留的待下载记录
                val pendingDocs = actualDocs.filter { it.parseStatus == 4 }
                for (p in pendingDocs) {
                    db.documentDao().delete(p)
                }
            }

            withContext(Dispatchers.Main) {
                if (!autoMode) {
                    Toast.makeText(this@WebViewActivity,
                        "下载完成: $downloaded/$totalExpected", Toast.LENGTH_SHORT).show()
                } else {
                    Log.d(TAG, "WebView auto mode: download complete $downloaded/$totalExpected")
                }
                finish()
            }
        }
    }

    /** 下载单个 PDF，返回 true 表示成功 */
    private suspend fun downloadOnePdf(url: String, displayName: String, useExistingDocId: Boolean): Boolean {
        val dir = File(filesDir, "pdfs").also { it.mkdirs() }
        val guessName = URLUtil.guessFileName(url, "", "application/pdf")
        val file = File(dir, "${System.currentTimeMillis()}_$guessName")

        val request = Request.Builder().url(url).build()
        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            Log.e(TAG, "WebView download failed: HTTP ${response.code}")
            return false
        }
        val contentType = response.header("Content-Type", "") ?: ""
        if (!contentType.contains("pdf", true) && !contentType.contains("octet-stream", true)
            && !url.lowercase().contains(".pdf")) {
            Log.d(TAG, "WebView: skipping non-PDF content-type=$contentType url=$url")
            return false
        }
        response.body?.byteStream()?.use { input ->
            file.outputStream().use { output -> input.copyTo(output) }
        }
        if (file.length() == 0L) { file.delete(); return false }
        Log.d(TAG, "WebView: downloaded ${file.length()} bytes -> ${file.name}")

        val db = (application as App).db
        val finalName = displayName.ifEmpty { guessName }

        // 去重：已下载过的跳过
        val existing = db.documentDao().findDownloadedByUrlAndSms(url, smsId)
        if (existing != null) {
            Log.d(TAG, "WebView: already downloaded url=$url, skip")
            file.delete()
            return false
        }

        if (useExistingDocId && docId > 0) {
            val doc = db.documentDao().getById(docId)
            if (doc != null) {
                db.documentDao().update(doc.copy(
                    fileName = guessName, filePath = file.absolutePath,
                    fileSize = file.length(), parseStatus = 0,
                    displayName = finalName
                ))
                PdfParser.parseAndSync(this@WebViewActivity, db, docId)
                docId = 0
                return true
            }
        }

        if (db.documentDao().findByUrlAndSms(url, smsId) != null) return false
        val newDocId = db.documentDao().insert(
            DocumentRecord(
                smsId = smsId, fileName = guessName, filePath = file.absolutePath,
                fileSize = file.length(), sourceUrl = url,
                downloadTime = System.currentTimeMillis(),
                displayName = finalName
            )
        )
        PdfParser.parseAndSync(this@WebViewActivity, db, newDocId)
        return true
    }

    override fun onDestroy() {
        scope.cancel()
        webView.destroy()
        super.onDestroy()
    }
}

