package com.shanfuchun.courtassistant.ui

import android.annotation.SuppressLint
import android.os.Bundle
import android.util.Log
import android.webkit.*
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.FileProvider
import com.shanfuchun.courtassistant.App
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.service.PdfParser
import kotlinx.coroutines.*
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONArray
import java.io.File
import java.util.concurrent.TimeUnit

class WebViewActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private val TAG = "CourtAssistant"
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private var smsId: Long = 0
    private var docId: Long = 0
    private var autoMode = false // 自动模式标志
    private val downloadedUrls = mutableSetOf<String>()
    private var scanComplete = false
    private var allLinksCollected = mutableListOf<Pair<String, String>>() // url, name

    private val client = OkHttpClient.Builder()
        .followRedirects(true)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .build()

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        webView = WebView(this)
        setContentView(webView)

        smsId = intent.getLongExtra("smsId", 0)
        docId = intent.getLongExtra("docId", 0)
        autoMode = intent.getBooleanExtra("autoMode", false)
        val url = intent.getStringExtra("url") ?: run { finish(); return }

        Log.d(TAG, "WebView: loading url=$url smsId=$smsId docId=$docId autoMode=$autoMode")
        if (!autoMode) {
            Toast.makeText(this, "正在扫描文档...", Toast.LENGTH_SHORT).show()
        }

        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            allowFileAccess = true
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
            userAgentString = "Mozilla/5.0 (Linux; Android 12) AppleWebKit/537.36 Chrome/120.0 Mobile Safari/537.36"
        }

        webView.addJavascriptInterface(JsBridge(), "CourtBridge")

        // 拦截浏览器触发的下载
        webView.setDownloadListener { downloadUrl, _, _, _, _ ->
            Log.d(TAG, "WebView download listener: $downloadUrl")
            synchronized(allLinksCollected) {
                if (!downloadedUrls.contains(downloadUrl)) {
                    allLinksCollected.add(downloadUrl to "")
                }
            }
        }

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView, request: WebResourceRequest): Boolean {
                val reqUrl = request.url.toString()
                if (reqUrl.lowercase().let { it.endsWith(".pdf") || it.contains("pdf") && it.contains("download") }) {
                    synchronized(allLinksCollected) {
                        if (!downloadedUrls.contains(reqUrl)) {
                            allLinksCollected.add(reqUrl to "")
                        }
                    }
                    return true
                }
                return false
            }

            override fun onPageFinished(view: WebView, url: String) {
                Log.d(TAG, "WebView page loaded: $url")
                // 多次扫描以捕获动态加载的内容
                val scanTimes = listOf(500, 1500, 3000, 5000, 8000, 12000, 15000)
                scanTimes.forEach { delay ->
                    view.postDelayed({ scanForPdfLinks(view) }, delay.toLong())
                }

                // 自动点击下载/查看按钮
                view.postDelayed({
                    view.evaluateJavascript("""
                        (function() {
                            var clicked = new Set();
                            // 点击所有可能触发下载的元素
                            var selectors = ['button', 'a.btn', '[class*="download"]',
                                            '[class*="btn"]', '[onclick]', 'a'];
                            for (var s = 0; s < selectors.length; s++) {
                                var elements = document.querySelectorAll(selectors[s]);
                                for (var i = 0; i < elements.length; i++) {
                                    var el = elements[i];
                                    var t = (el.innerText || el.textContent || '').trim();
                                    var hasKeyword = t.indexOf('下载') >= 0 || t.indexOf('查看') >= 0 ||
                                                   t.indexOf('传票') >= 0 || t.indexOf('文书') >= 0 ||
                                                   t.indexOf('打印') >= 0;
                                    if (hasKeyword && !clicked.has(el)) {
                                        clicked.add(el);
                                        try { el.click(); } catch(e) {}
                                    }
                                }
                            }
                            return clicked.size;
                        })()
                    """.trimIndent()) { result ->
                        Log.d(TAG, "WebView auto-clicked buttons: $result")
                    }
                }, 2000)

                // 最终确认并开始下载
                view.postDelayed({
                    scanComplete = true
                    startBatchDownload()
                }, 18000) // 18秒后开始下载
            }
        }

        webView.loadUrl(url)

        // 超时保底
        scope.launch {
            delay(60000)
            if (!isFinishing) {
                Log.d(TAG, "WebView: timeout")
                if (allLinksCollected.isNotEmpty() && !scanComplete) {
                    scanComplete = true
                    startBatchDownload()
                } else {
                    if (!autoMode) {
                        Toast.makeText(this@WebViewActivity, "页面加载超时", Toast.LENGTH_SHORT).show()
                    }
                    finish()
                }
            }
        }
    }

    private val JS_SCAN = """
        (function() {
            var results = [];
            var seen = new Set();

            // 辅助函数：添加结果（去重）
            function addResult(url, name) {
                if (!url || url === '#' || url === 'javascript:;') return;
                // 标准化URL
                var cleanUrl = url.split('#')[0].split('?')[0];
                if (!seen.has(cleanUrl)) {
                    seen.add(cleanUrl);
                    results.push({url: url, name: name || cleanUrl});
                }
            }

            // 扫描所有链接
            var links = document.querySelectorAll('a[href], a[onclick], [class*="download"], [class*="btn"], [data-href]');
            for (var i = 0; i < links.length; i++) {
                var link = links[i];
                var href = link.href || link.getAttribute('data-href') || link.getAttribute('onclick') || '';
                var text = (link.innerText || link.textContent || link.title || '').trim();
                var className = (link.className || '').toLowerCase();
                var lower = href.toLowerCase();

                // 判断是否为PDF链接或下载按钮
                var isPdf = lower.indexOf('.pdf') >= 0 || lower.indexOf('pdf') >= 0;
                var hasKeyword = text.indexOf('下载') >= 0 || text.indexOf('查看') >= 0 ||
                                text.indexOf('传票') >= 0 || text.indexOf('文书') >= 0 ||
                                text.indexOf('判决') >= 0 || text.indexOf('裁定') >= 0 ||
                                text.indexOf('送达') >= 0 || text.indexOf('通知') >= 0 ||
                                text.indexOf('应诉') >= 0 || text.indexOf('开庭') >= 0 ||
                                className.indexOf('download') >= 0 || className.indexOf('file') >= 0;

                if (isPdf || hasKeyword) {
                    var displayName = text;
                    // 如果文本为空，尝试从属性获取
                    if (!displayName) {
                        displayName = link.getAttribute('title') || link.getAttribute('data-name') || '';
                    }
                    // 如果还是空，提取URL中的文件名
                    if (!displayName) {
                        var match = href.match(/([^\/]+)\.pdf/i);
                        displayName = match ? match[1] : '文档';
                    }
                    addResult(href, displayName);
                }
            }

            // 扫描按钮（可能通过onclick触发下载）
            var buttons = document.querySelectorAll('button, [role="button"]');
            for (var j = 0; j < buttons.length; j++) {
                var btn = buttons[j];
                var text = (btn.innerText || btn.textContent || '').trim();
                var onClick = btn.getAttribute('onclick') || '';

                if (text.indexOf('下载') >= 0 || text.indexOf('查看') >= 0 ||
                    text.indexOf('传票') >= 0 || text.indexOf('文书') >= 0 ||
                    (onClick && onClick.toLowerCase().indexOf('pdf') >= 0)) {
                    // 尝试从onclick提取URL
                    var urlMatch = onClick.match(/['"]([^'"]*\.pdf[^'"]*)['"]/i);
                    if (urlMatch) {
                        addResult(urlMatch[1], text || '文档');
                    } else {
                        // 标记需要点击的按钮
                        addResult('CLICK_NEEDED:' + text, text || '文档');
                    }
                }
            }

            // 扫描iframe和embed
            var iframes = document.querySelectorAll('iframe[src], embed[src], object[data]');
            for (var k = 0; k < iframes.length; k++) {
                var src = iframes[k].src || iframes[k].data || '';
                if (src.toLowerCase().indexOf('pdf') >= 0) {
                    addResult(src, '嵌入文档');
                }
            }

            // 扫描所有可能的PDF URL（包括在script中）
            var scripts = document.querySelectorAll('script');
            for (var s = 0; s < scripts.length; s++) {
                var scriptText = scripts[s].textContent;
                if (scriptText && scriptText.toLowerCase().indexOf('.pdf') >= 0) {
                    var matches = scriptText.match(/(['"])(https?:[^'"]*\.pdf[^'"]*)\1/gi);
                    if (matches) {
                        for (var m = 0; m < matches.length; m++) {
                            var url = matches[m].replace(/['"]/g, '');
                            addResult(url, '');
                        }
                    }
                }
            }

            return JSON.stringify(results);
        })()
    """.trimIndent()

    private fun scanForPdfLinks(view: WebView) {
        view.evaluateJavascript(JS_SCAN) { result ->
            try {
                val json = result?.trim()?.removeSurrounding("\"")
                    ?.replace("\\\"", "\"")?.replace("\\\\", "\\")
                if (json.isNullOrBlank() || json == "null" || json == "[]") return@evaluateJavascript
                val arr = JSONArray(json)
                synchronized(allLinksCollected) {
                    for (i in 0 until arr.length()) {
                        val obj = arr.getJSONObject(i)
                        val pdfUrl = obj.getString("url")
                        var name = obj.optString("name", "")

                        // 处理需要点击的按钮
                        if (pdfUrl.startsWith("CLICK_NEEDED:")) {
                            val buttonText = pdfUrl.substringAfter("CLICK_NEEDED:")
                            Log.d(TAG, "WebView scan: found clickable button: $buttonText")
                            // 尝试通过JavaScript点击按钮
                            tryClickButtonByText(view, buttonText)
                            continue
                        }

                        // 确保name不为空
                        if (name.isBlank()) {
                            name = extractNameFromUrl(pdfUrl)
                        }

                        if (pdfUrl.isNotBlank() && !downloadedUrls.contains(pdfUrl)
                            && allLinksCollected.none { it.first == pdfUrl }) {
                            allLinksCollected.add(pdfUrl to name)
                            Log.d(TAG, "WebView scan: added PDF - url=$pdfUrl name=$name")
                        }
                    }
                }
                Log.d(TAG, "WebView scan: total ${allLinksCollected.size} links found")
            } catch (e: Exception) {
                Log.e(TAG, "WebView scan parse error", e)
            }
        }
    }

    /** 尝试通过JavaScript点击包含指定文本的按钮 */
    private fun tryClickButtonByText(view: WebView, text: String) {
        val js = """
            (function() {
                var buttons = document.querySelectorAll('button, [role="button"], a');
                for (var i = 0; i < buttons.length; i++) {
                    var btnText = (buttons[i].innerText || buttons[i].textContent || '').trim();
                    if (btnText.indexOf('$text') >= 0) {
                        buttons[i].click();
                        return true;
                    }
                }
                return false;
            })()
        """.trimIndent()
        view.evaluateJavascript(js) { result ->
            Log.d(TAG, "tryClickButtonByText: clicked=$result text=$text")
        }
    }

    /** 从URL提取文件名 */
    private fun extractNameFromUrl(url: String): String {
        return try {
            val path = url.substringBefore("?").substringAfterLast("/")
            if (path.isNotBlank() && path.length < 100) {
                path.removeSuffix(".pdf").removeSuffix(".PDF")
            } else {
                "文档"
            }
        } catch (e: Exception) {
            "文档"
        }
    }

    inner class JsBridge {
        @JavascriptInterface
        fun onPdfLinksFound(json: String) {
            // 保留兼容，但主要靠 scanForPdfLinks
            Log.d(TAG, "WebView JsBridge: $json")
        }
    }

    private fun startBatchDownload() {
        val links: List<Pair<String, String>>
        synchronized(allLinksCollected) {
            links = allLinksCollected.toList()
        }
        if (links.isEmpty()) {
            if (!autoMode) {
                Toast.makeText(this, "未发现PDF文档", Toast.LENGTH_SHORT).show()
            }
            finish()
            return
        }
        Log.d(TAG, "WebView: starting batch download of ${links.size} files")
        if (!autoMode) {
            Toast.makeText(this, "发现 ${links.size} 个文档，开始下载...", Toast.LENGTH_SHORT).show()
        }

        scope.launch(Dispatchers.IO) {
            var firstDocHandled = false
            var downloaded = 0
            val totalExpected = links.size
            for ((url, name) in links) {
                if (downloadedUrls.contains(url)) continue
                downloadedUrls.add(url)
                try {
                    val result = downloadOnePdf(url, name, !firstDocHandled)
                    if (result) {
                        firstDocHandled = true
                        downloaded++
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "WebView batch download error: $url", e)
                }
            }

            // 监督机制：对比实际下载数量与源网页数量
            val db = (application as App).db
            val actualDocs = db.documentDao().getBySmsIdSync(smsId)
            val downloadedDocs = actualDocs.filter { it.parseStatus != 4 && it.filePath.isNotEmpty() }
            Log.d(TAG, "WebView: expected=$totalExpected downloaded=$downloaded actual=${downloadedDocs.size}")

            if (downloadedDocs.size < totalExpected) {
                // 未下载完全，保留/更新待下载记录以便用户重试
                val pendingExists = actualDocs.any { it.parseStatus == 4 }
                if (!pendingExists) {
                    val sourceUrl = intent.getStringExtra("url") ?: ""
                    if (sourceUrl.isNotEmpty()) {
                        val label = "未下载完全(${downloadedDocs.size}/$totalExpected) 点击重试"
                        db.documentDao().insert(
                            DocumentRecord(
                                smsId = smsId, fileName = label, filePath = "",
                                fileSize = 0, sourceUrl = sourceUrl,
                                downloadTime = System.currentTimeMillis(), parseStatus = 4,
                                displayName = label
                            )
                        )
                    }
                }
            } else {
                // 全部下载完成，删除残留的待下载记录
                val pendingDocs = actualDocs.filter { it.parseStatus == 4 }
                for (p in pendingDocs) {
                    db.documentDao().delete(p)
                }
            }

            withContext(Dispatchers.Main) {
                if (!autoMode) {
                    Toast.makeText(this@WebViewActivity,
                        "下载完成: $downloaded/$totalExpected", Toast.LENGTH_SHORT).show()
                } else {
                    Log.d(TAG, "WebView auto mode: download complete $downloaded/$totalExpected")
                }
                finish()
            }
        }
    }

    /** 下载单个 PDF，返回 true 表示成功 */
    private suspend fun downloadOnePdf(url: String, displayName: String, useExistingDocId: Boolean): Boolean {
        val dir = File(filesDir, "pdfs").also { it.mkdirs() }
        val guessName = URLUtil.guessFileName(url, "", "application/pdf")
        val file = File(dir, "${System.currentTimeMillis()}_$guessName")

        val request = Request.Builder().url(url).build()
        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            Log.e(TAG, "WebView download failed: HTTP ${response.code}")
            return false
        }
        val contentType = response.header("Content-Type", "") ?: ""
        if (!contentType.contains("pdf", true) && !contentType.contains("octet-stream", true)
            && !url.lowercase().contains(".pdf")) {
            Log.d(TAG, "WebView: skipping non-PDF content-type=$contentType url=$url")
            return false
        }
        response.body?.byteStream()?.use { input ->
            file.outputStream().use { output -> input.copyTo(output) }
        }
        if (file.length() == 0L) { file.delete(); return false }
        Log.d(TAG, "WebView: downloaded ${file.length()} bytes -> ${file.name}")

        val db = (application as App).db
        val finalName = displayName.ifEmpty { guessName }

        // 去重：已下载过的跳过
        val existing = db.documentDao().findDownloadedByUrlAndSms(url, smsId)
        if (existing != null) {
            Log.d(TAG, "WebView: already downloaded url=$url, skip")
            file.delete()
            return false
        }

        if (useExistingDocId && docId > 0) {
            val doc = db.documentDao().getById(docId)
            if (doc != null) {
                db.documentDao().update(doc.copy(
                    fileName = guessName, filePath = file.absolutePath,
                    fileSize = file.length(), parseStatus = 0,
                    displayName = finalName
                ))
                PdfParser.parseAndSync(this@WebViewActivity, db, docId)
                docId = 0
                return true
            }
        }

        if (db.documentDao().findByUrlAndSms(url, smsId) != null) return false
        val newDocId = db.documentDao().insert(
            DocumentRecord(
                smsId = smsId, fileName = guessName, filePath = file.absolutePath,
                fileSize = file.length(), sourceUrl = url,
                downloadTime = System.currentTimeMillis(),
                displayName = finalName
            )
        )
        PdfParser.parseAndSync(this@WebViewActivity, db, newDocId)
        return true
    }

    override fun onDestroy() {
        scope.cancel()
        webView.destroy()
        super.onDestroy()
    }
}

