@Dao
interface SmsDao {
    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    fun getAll(): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    suspend fun getAllSync(): List<SmsRecord>

    @Query("SELECT * FROM sms_record WHERE body LIKE '%' || :q || '%' OR sender LIKE '%' || :q || '%' ORDER BY receiveTime DESC")
    fun search(q: String): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record WHERE id = :id")
    suspend fun getById(id: Long): SmsRecord?

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insert(record: SmsRecord): Long

    @Update
    suspend fun update(record: SmsRecord)

    @Query("SELECT MAX(receiveTime) FROM sms_record")
    suspend fun getLatestTime(): Long?
}

@Dao
interface DocumentDao {
    @Query("SELECT * FROM document_record WHERE smsId = :smsId ORDER BY downloadTime DESC")
