override fun onPageFinished(view: WebView, url: String) {
    Log.d(TAG, "WebView page loaded: $url")
    // 多次扫描以捕获动态加载的内容
    val scanTimes = listOf(500, 1500, 3000, 5000, 8000, 12000, 15000)
    scanTimes.forEach { delay ->
        view.postDelayed({ scanForPdfLinks(view) }, delay.toLong())
    }

    // 自动点击下载/查看按钮
    view.postDelayed({
        view.evaluateJavascript("""
            (function() {
                var clicked = new Set();
                // 点击所有可能触发下载的元素
                var selectors = ['button', 'a.btn', '[class*="download"]',
                                '[class*="btn"]', '[onclick]', 'a'];
                for (var s = 0; s < selectors.length; s++) {
                    var elements = document.querySelectorAll(selectors[s]);
                    for (var i = 0; i < elements.length; i++) {
                        var el = elements[i];
                        var t = (el.innerText || el.textContent || '').trim();
                        var hasKeyword = t.indexOf('下载') >= 0 || t.indexOf('查看') >= 0 ||
                                       t.indexOf('传票') >= 0 || t.indexOf('文书') >= 0 ||
                                       t.indexOf('打印') >= 0;
                        if (hasKeyword && !clicked.has(el)) {
                            clicked.add(el);
                            try { el.click(); } catch(e) {}
                        }
                    }
                }
                return clicked.size;
            })()
        """.trimIndent()) { result ->
            Log.d(TAG, "WebView auto-clicked buttons: $result")
        }
    }, 2000)

    // 最终确认并开始下载
    view.postDelayed({
        scanComplete = true
        startBatchDownload()
    }, 18000) // 18秒后开始下载
}

