private fun autoClickPdfLinks(view: WebView) {
    val js = """
        (function() {
            var clicked = new Set();
            var clickCount = 0;

            // 法院文档关键词
            var docKeywords = ['传票', '通知书', '举证', '受理', '判决', '裁定',
                              '送达', '应诉', '起诉', '答辩', '告知', '决定', '文书'];

            // 查找所有可能是PDF的链接
            function tryClickPdfLinks() {
                var links = document.querySelectorAll('a, [onclick], [class*="file"], [class*="document"], [class*="item"], [class*="list"] > *');
                var pdfCount = 0;

                for (var i = 0; i < links.length; i++) {
                    var link = links[i];
                    if (clicked.has(link)) continue;

                    var href = link.href || link.getAttribute('data-href') || '';
                    var text = (link.innerText || link.textContent || '').trim();
                    var className = link.className || '';
                    var lowerHref = href.toLowerCase();
                    var lowerText = text.toLowerCase();
                    var lowerClass = className.toLowerCase();

                    // 判断是否为PDF文档链接
                    var isPdfLink = lowerHref.indexOf('.pdf') >= 0 ||
                                     lowerHref.indexOf('pdf') >= 0 ||
                                     lowerText.indexOf('.pdf') >= 0 ||
                                     lowerText.indexOf('PDF') >= 0;

                    // 检查是否包含文档关键词
                    var hasDocKeyword = docKeywords.some(function(kw) {
                        return lowerText.indexOf(kw) >= 0 || lowerClass.indexOf(kw) >= 0;
                    });

                    // 检查是否为文件列表项
                    var isFileItem = lowerClass.indexOf('file') >= 0 ||
                                     lowerClass.indexOf('doc') >= 0 ||
                                     lowerClass.indexOf('item') >= 0 ||
                                     lowerClass.indexOf('list') >= 0;

                    // 如果是PDF链接、包含文档关键词或是文件列表项，则点击
                    if ((isPdfLink || hasDocKeyword || isFileItem) &&
                        href && href !== '#' && href !== 'javascript:;' && href !== 'javascript:void(0)') {
                        clicked.add(link);
                        clickCount++;
                        pdfCount++;
