   178→                            var text = (element.innerText || element.textContent || '').trim();
   179→                            var className = element.className || '';
   180→                            var id = element.id || '';
   181→
   182→                            // 获取父元素的class
   183→                            var parentClass = '';
   184→                            if (element.parentElement) {
   185→                                parentClass = element.parentElement.className || '';
   186→                            }
   187→
   188→                            var lowerHref = href.toLowerCase();
   189→                            var lowerText = text.toLowerCase();
   190→                            var lowerClass = className.toLowerCase();
   191→                            var lowerParent = parentClass.toLowerCase();
   192→
   193→                            // 判断是否为PDF文档链接
   194→                            var isPdfLink = lowerHref.indexOf('.pdf') >= 0 ||
   195→                                                   lowerHref.indexOf('pdf') >= 0 ||
   196→                                                   lowerHref.indexOf('download') >= 0;
   197→
   198→                            // 检查是否包含文档关键词
   199→                            var hasDocKeyword = docKeywords.some(function(kw) {
   200→                                return lowerText.indexOf(kw) >= 0 || lowerClass.indexOf(kw) >= 0 ||
   201→                                       lowerParent.indexOf(kw) >= 0 || id.indexOf(kw) >= 0;
   202→                            });
   203→
   204→                            // 检查是否为文件列表项
   205→                            var isFileItem = lowerClass.indexOf('file') >= 0 ||
   206→                                                   lowerClass.indexOf('doc') >= 0 ||
   207→                                                   lowerClass.indexOf('item') >= 0 ||
   208→                                                   lowerClass.indexOf('card') >= 0 ||
   209→                                                   lowerParent.indexOf('list') >= 0;
   210→
   211→                            // 如果是PDF链接、包含文档关键词或是文件列表项
   212→                            if ((isPdfLink || hasDocKeyword || isFileItem) && href && href !== '#' &&
   213→                                href !== 'javascript:;' && href !== 'javascript:void(0)' && href.length > 10) {
   214→
   215→                                clicked.add(element);
   216→                                clickCount++;
   217→
   218→                                // 通知Java层
   219→                                if (window.CourtBridge && window.CourtBridge.onPdfLinkClicked) {
   220→                                    window.CourtBridge.onPdfLinkClicked(href, text);
   221→                                }
   222→
   223→                                foundLinks.push({url: href, name: text});
   224→                                console.log('Found PDF:', text, href);
   225→
   226→                                // 点击元素
   227→                                try {
   228→                                    element.click();
   229→                                } catch(e) {
   230→                                    console.error('Click error:', e);
   231→                                }
   232→                            }
   233→                        }
   234→
   235→                        return foundLinks.length;
   236→                    }
   237→
   238→                    // 首次查找
   239→                    var firstCount = findAndClickElements();
   240→                    console.log('First scan: found', firstCount, 'PDFs');
   241→
   242→                    // 多次延迟查找（处理动态加载内容）
   243→                    var delays = [2000, 4000, 6000, 8000, 10000];
   244→                    delays.forEach(function(delay) {
   245→                        setTimeout(function() {
   246→                            var count = findAndClickElements();
   247→                            console.log('Scan at ' + delay + 'ms: found', count, 'PDFs');
   248→                        }, delay);
   249→                    });
   250→
   251→                    // 最终汇总
   252→                    setTimeout(function() {
   253→                        console.log('Total unique PDFs found:', foundLinks.length);
   254→                        console.log('All PDFs:', foundLinks);
   255→                    }, 12000);
   256→
   257→                    return {count: foundLinks.length, links: foundLinks};
   258→                })()
   259→            """.trimIndent()
   260→
   261→            view.evaluateJavascript(js) { result ->
   262→                Log.d(TAG, "autoClickPdfLinks: $result")
   263→            }
   264→        }
   265→        }
   266→
   267→        webView.loadUrl(url)
   268→
   269→        // 超时保底（90秒，足够完成所有扫描和下载）
   270→        scope.launch {
   271→            delay(90000)
   272→            if (!isFinishing) {
   273→                Log.d(TAG, "WebView: timeout")
   274→                if (allLinksCollected.isNotEmpty() && !scanComplete) {
   275→                    scanComplete = true
   276→                    startBatchDownload()
   277→                } else {
   278→                    if (!autoMode) {
   279→                        Toast.makeText(this@WebViewActivity, "页面加载超时", Toast.LENGTH_SHORT).show()
   280→                    }
   281→                    finish()
   282→                }
   283→            }
   284→        }
   285→    }
   286→
   287→    private val JS_SCAN = """
   288→        (function() {
   289→            var results = [];
   290→            var seen = new Set();
   291→
   292→            // 辅助函数：添加结果（去重）
   293→            function addResult(url, name) {
   294→                if (!url || url === '#' || url === 'javascript:;' || url === 'javascript:void(0)') return;
   295→                // 标准化URL
   296→                var cleanUrl = url.split('#')[0].split('?')[0];
   297→                if (!seen.has(cleanUrl)) {
   298→                    seen.add(cleanUrl);
   299→                    results.push({url: url, name: name || cleanUrl});
   300→                }
   301→            }
   302→
   303→            // 法院文书关键词（包含文件类型关键词）
   304→            var keywords = ['下载', '查看', '传票', '文书', '判决', '裁定', '送达', '通知',
   305→                           '应诉', '开庭', '举证', '受理', '讼', '案件', '起诉', '答辩',
   306→                           '通知书', '告知书', '决定书'];
   307→
   308→            // 扫描所有链接和可点击元素
   309→            var selectors = ['a[href]', 'a[onclick]', '[class*="download"]', '[class*="btn"]',
   310→                           '[data-href]', '[onclick]', '.file-item', '.document-item',
   311→                           '.pdf-item', '[class*="file"]', '[class*="doc"]'];
   312→            var links = document.querySelectorAll(selectors.join(', '));
   313→
   314→            for (var i = 0; i < links.length; i++) {
   315→                var link = links[i];
   316→                var href = link.href || link.getAttribute('data-href') || link.getAttribute('onclick') || '';
   317→                var text = (link.innerText || link.textContent || '').trim();
   318→                var title = link.getAttribute('title') || '';
   319→                var className = (link.className || '').toLowerCase();
   320→                var lower = href.toLowerCase();
   321→                var lowerText = text.toLowerCase();
   322→                var lowerTitle = title.toLowerCase();
   323→
   324→                // 判断是否为PDF链接或文档链接
   325→                var isPdfLink = lower.indexOf('.pdf') >= 0 || lower.indexOf('pdf') >= 0 ||
   326→                                 lower.indexOf('download') >= 0 || lower.indexOf('file') >= 0;
   327→
   328→                // 检查是否包含文书关键词
   329→                var hasKeyword = keywords.some(function(kw) {
   330→                    return lowerText.indexOf(kw) >= 0 || lowerTitle.indexOf(kw) >= 0 ||
   331→                           className.indexOf(kw) >= 0;
   332→                });
   333→
   334→                // 检查是否为文件列表项
   335→                var isFileItem = className.indexOf('file') >= 0 ||
   336→                                 className.indexOf('document') >= 0 ||
   337→                                 className.indexOf('doc') >= 0 ||
   338→                                 className.indexOf('item') >= 0;
   339→
   340→                if (isPdfLink || hasKeyword || isFileItem) {
   341→                    // 文件名就是显示的文本（如：举证通知书（临沂昀鑫置业有限公司）.pdf）
   342→                    var displayName = text || title;
   343→
   344→                    // 如果没有显示名称，尝试从属性获取
   345→                    if (!displayName) {
   346→                        displayName = link.getAttribute('data-name') ||
   347→                                     link.getAttribute('data-title') ||
   348→                                     link.getAttribute('aria-label') || '';
   349→                    }
   350→
   351→                    // 如果还是没有名称且有关键词，使用关键词
   352→                    if (!displayName && hasKeyword) {
   353→                        displayName = text || title || '法律文书';
   354→                    }
   355→
   356→                    // 确保有名称用于显示
   357→                    if (displayName) {
   358→                        addResult(href, displayName);
   359→                    }
   360→                }
   361→            }
   362→
   363→            // 扫描按钮（可能通过onclick触发下载）
   364→            var buttons = document.querySelectorAll('button, [role="button"]');
   365→            for (var j = 0; j < buttons.length; j++) {
   366→                var btn = buttons[j];
   367→                var btnText = (btn.innerText || btn.textContent || '').trim();
   368→                var onClick = btn.getAttribute('onclick') || '';
   369→                var btnClass = (btn.className || '').toLowerCase();
   370→
   371→                var hasButtonKeyword = keywords.some(function(kw) {
   372→                    return btnText.indexOf(kw) >= 0 || btnClass.indexOf(kw) >= 0;
   373→                });
   374→
   375→                if (hasButtonKeyword || (onClick && onClick.toLowerCase().indexOf('pdf') >= 0)) {
   376→                    // 尝试从onclick提取URL
   377→                    var urlMatch = onClick.match(/['"]([^'"]*\.pdf[^'"]*)['"]/i);
   378→                    if (urlMatch) {
   379→                        addResult(urlMatch[1], btnText || '文档');
   380→                    } else {
   381→                        // 标记需要点击的按钮
   382→                        addResult('CLICK_NEEDED:' + btnText, btnText || '文档');
   383→                    }
   384→                }
   385→            }
   386→
   387→            // 扫描iframe和embed
   388→            var iframes = document.querySelectorAll('iframe[src], embed[src], object[data]');
   389→            for (var k = 0; k < iframes.length; k++) {
   390→                var src = iframes[k].src || iframes[k].data || '';
   391→                if (src.toLowerCase().indexOf('pdf') >= 0) {
   392→                    addResult(src, '嵌入文档');
   393→                }
   394→            }
   395→
   396→            // 扫描所有可能的PDF URL（包括在script中）
   397→            var scripts = document.querySelectorAll('script');
   398→            for (var s = 0; s < scripts.length; s++) {
   399→                var scriptText = scripts[s].textContent;
   400→                if (scriptText && scriptText.toLowerCase().indexOf('.pdf') >= 0) {
   401→                    var matches = scriptText.match(/(['"])(https?:[^'"]*\.pdf[^'"]*)\1/gi);
   402→                    if (matches) {
   403→                        for (var m = 0; m < matches.length; m++) {
   404→                            var url = matches[m].replace(/['"]/g, '');
   405→                            addResult(url, '');
   406→                        }
   407→                    }
   408→                }
   409→            }
   410→
   411→            return JSON.stringify(results);
   412→        })()
   413→    """.trimIndent()
   414→
   415→    private fun scanForPdfLinks(view: WebView) {
   416→        view.evaluateJavascript(JS_SCAN) { result ->
   417→            try {
   418→                val json = result?.trim()?.removeSurrounding("\"")
   419→                    ?.replace("\\\"", "\"")?.replace("\\\\", "\\")
   420→                if (json.isNullOrBlank() || json == "null" || json == "[]") return@evaluateJavascript
   421→                val arr = JSONArray(json)
   422→                synchronized(allLinksCollected) {
   423→                    for (i in 0 until arr.length()) {
   424→                        val obj = arr.getJSONObject(i)
   425→                        val pdfUrl = obj.getString("url")
   426→                        var name = obj.optString("name", "")
   427→
   428→                        // 处理需要点击的按钮
   429→                        if (pdfUrl.startsWith("CLICK_NEEDED:")) {
   430→                            val buttonText = pdfUrl.substringAfter("CLICK_NEEDED:")
   431→                            Log.d(TAG, "WebView scan: found clickable button: $buttonText")
   432→                            // 尝试通过JavaScript点击按钮
   433→                            tryClickButtonByText(view, buttonText)
   434→                            continue
   435→                        }
   436→
   437→                        // 确保name不为空
   438→                        if (name.isBlank()) {
   439→                            name = extractNameFromUrl(pdfUrl)
   440→                        }
   441→
   442→                        if (pdfUrl.isNotBlank() && !downloadedUrls.contains(pdfUrl)
   443→                            && allLinksCollected.none { it.first == pdfUrl }) {
   444→                            allLinksCollected.add(pdfUrl to name)
   445→                            Log.d(TAG, "WebView scan: added PDF - url=$pdfUrl name=$name")
   446→                        }
   447→                    }
   448→                }
   449→                Log.d(TAG, "WebView scan: total ${allLinksCollected.size} links found")
   450→            } catch (e: Exception) {
   451→                Log.e(TAG, "WebView scan parse error", e)
   452→            }
   453→        }
   454→    }
   455→
   456→    /** 尝试通过JavaScript点击包含指定文本的按钮 */
   457→    private fun tryClickButtonByText(view: WebView, text: String) {
   458→        val js = """
   459→            (function() {
   460→                var buttons = document.querySelectorAll('button, [role="button"], a');
   461→                for (var i = 0; i < buttons.length; i++) {
   462→                    var btnText = (buttons[i].innerText || buttons[i].textContent || '').trim();
   463→                    if (btnText.indexOf('$text') >= 0) {
   464→                        buttons[i].click();
   465→                        return true;
   466→                    }
   467→                }
   468→                return false;
   469→            })()
   470→        """.trimIndent()
   471→        view.evaluateJavascript(js) { result ->
   472→            Log.d(TAG, "tryClickButtonByText: clicked=$result text=$text")
   473→        }
   474→    }
   475→
   476→    /** 从URL提取文件名 */
   477→    private fun extractNameFromUrl(url: String): String {
   478→        return try {
   479→            val path = url.substringBefore("?").substringAfterLast("/")
   480→            if (path.isNotBlank() && path.length < 100) {
   481→                path.removeSuffix(".pdf").removeSuffix(".PDF")
   482→            } else {
   483→                "文档"
   484→            }
   485→        } catch (e: Exception) {
   486→            "文档"
   487→        }
   488→    }
   489→
   490→    inner class JsBridge {
   491→        @JavascriptInterface
   492→        fun onPdfLinksFound(json: String) {
   493→            // 保留兼容，但主要靠 scanForPdfLinks
   494→            Log.d(TAG, "WebView JsBridge: $json")
   495→        }
   496→
   497→        @JavascriptInterface
   498→        fun onPdfLinkClicked(url: String, name: String) {
   499→            Log.d(TAG, "WebView JsBridge: PDF link clicked - url=$url name=$name")
   500→            synchronized(allLinksCollected) {
   501→                if (!downloadedUrls.contains(url) &&
   502→                    allLinksCollected.none { it.first == url }) {
   503→                    allLinksCollected.add(url to name)
   504→                    Log.d(TAG, "WebView JsBridge: Added PDF - url=$url name=$name")
   505→                }
   506→            }
   507→        }
   508→    }
   509→
   510→    private fun startBatchDownload() {
   511→        val links: List<Pair<String, String>>
   512→        synchronized(allLinksCollected) {
   513→            links = allLinksCollected.toList()
   514→        }
   515→        if (links.isEmpty()) {
   516→            if (!autoMode) {
   517→                Toast.makeText(this, "未发现PDF文档", Toast.LENGTH_SHORT).show()
   518→            }
   519→            finish()
   520→            return
   521→        }
   522→        Log.d(TAG, "WebView: starting batch download of ${links.size} files")
   523→        if (!autoMode) {
   524→            Toast.makeText(this, "发现 ${links.size} 个文档，开始下载...", Toast.LENGTH_SHORT).show()
   525→        }
   526→
   527→        scope.launch(Dispatchers.IO) {
   528→            var firstDocHandled = false
   529→            var downloaded = 0
   530→            val totalExpected = links.size
   531→            for ((url, name) in links) {
   532→                if (downloadedUrls.contains(url)) continue
   533→                downloadedUrls.add(url)
   534→                try {
   535→                    val result = downloadOnePdf(url, name, !firstDocHandled)
   536→                    if (result) {
   537→                        firstDocHandled = true
   538→                        downloaded++
   539→                    }
   540→                } catch (e: Exception) {
   541→                    Log.e(TAG, "WebView batch download error: $url", e)
   542→                }
   543→            }
   544→
   545→            // 监督机制：对比实际下载数量与源网页数量
   546→            val db = (application as App).db
   547→            val actualDocs = db.documentDao().getBySmsIdSync(smsId)
   548→            val downloadedDocs = actualDocs.filter { it.parseStatus != 4 && it.filePath.isNotEmpty() }
   549→            Log.d(TAG, "WebView: expected=$totalExpected downloaded=$downloaded actual=${downloadedDocs.size}")
   550→
   551→            if (downloadedDocs.size < totalExpected) {
   552→                // 未下载完全，保留/更新待下载记录以便用户重试
   553→                val pendingExists = actualDocs.any { it.parseStatus == 4 }
   554→                if (!pendingExists) {
   555→                    val sourceUrl = intent.getStringExtra("url") ?: ""
   556→                    if (sourceUrl.isNotEmpty()) {
   557→                        val label = "未下载完全(${downloadedDocs.size}/$totalExpected) 点击重试"
   558→                        db.documentDao().insert(
   559→                            DocumentRecord(
   560→                                smsId = smsId, fileName = label, filePath = "",
   561→                                fileSize = 0, sourceUrl = sourceUrl,
   562→                                downloadTime = System.currentTimeMillis(), parseStatus = 4,
   563→                                displayName = label
   564→                            )
   565→                        )
   566→                    }
   567→                }
   568→            } else {
   569→                // 全部下载完成，删除残留的待下载记录
   570→                val pendingDocs = actualDocs.filter { it.parseStatus == 4 }
   571→                for (p in pendingDocs) {
   572→                    db.documentDao().delete(p)
   573→                }
   574→            }
   575→
   576→            withContext(Dispatchers.Main) {
   577→                if (!autoMode) {
   578→                    Toast.makeText(this@WebViewActivity,
   579→                        "下载完成: $downloaded/$totalExpected", Toast.LENGTH_SHORT).show()
   580→                } else {
   581→                    Log.d(TAG, "WebView auto mode: download complete $downloaded/$totalExpected")
   582→                }
   583→                finish()
   584→            }
   585→        }
   586→    }
   587→
   588→    /** 下载单个 PDF，返回 true 表示成功 */
   589→    private suspend fun downloadOnePdf(url: String, displayName: String, useExistingDocId: Boolean): Boolean {
   590→        val dir = File(filesDir, "pdfs").also { it.mkdirs() }
   591→        val guessName = URLUtil.guessFileName(url, "", "application/pdf")
   592→        val file = File(dir, "${System.currentTimeMillis()}_$guessName")
   593→
   594→        val request = Request.Builder().url(url).build()
   595→        val response = client.newCall(request).execute()
   596→        if (!response.isSuccessful) {
   597→            Log.e(TAG, "WebView download failed: HTTP ${response.code}")
   598→            return false
   599→        }
   600→        val contentType = response.header("Content-Type", "") ?: ""
   601→        if (!contentType.contains("pdf", true) && !contentType.contains("octet-stream", true)
   602→            && !url.lowercase().contains(".pdf")) {
   603→            Log.d(TAG, "WebView: skipping non-PDF content-type=$contentType url=$url")
   604→            return false
   605→        }
   606→        response.body?.byteStream()?.use { input ->
   607→            file.outputStream().use { output -> input.copyTo(output) }
   608→        }
   609→        if (file.length() == 0L) { file.delete(); return false }
   610→        Log.d(TAG, "WebView: downloaded ${file.length()} bytes -> ${file.name}")
   611→
   612→        val db = (application as App).db
   613→        val finalName = displayName.ifEmpty { guessName }
   614→
   615→        // 去重：已下载过的跳过
   616→        val existing = db.documentDao().findDownloadedByUrlAndSms(url, smsId)
   617→        if (existing != null) {
   618→            Log.d(TAG, "WebView: already downloaded url=$url, skip")
   619→            file.delete()
   620→            return false
   621→        }
   622→
   623→        if (useExistingDocId && docId > 0) {
   624→            val doc = db.documentDao().getById(docId)
   625→            if (doc != null) {
   626→                db.documentDao().update(doc.copy(
   627→                    fileName = guessName, filePath = file.absolutePath,
   628→                    fileSize = file.length(), parseStatus = 0,
   629→                    displayName = finalName
   630→                ))
   631→                PdfParser.parseAndSync(this@WebViewActivity, db, docId)
   632→                docId = 0
   633→                return true
   634→            }
   635→        }
   636→
   637→        if (db.documentDao().findByUrlAndSms(url, smsId) != null) return false
   638→        val newDocId = db.documentDao().insert(
   639→            DocumentRecord(
   640→                smsId = smsId, fileName = guessName, filePath = file.absolutePath,
   641→                fileSize = file.length(), sourceUrl = url,
   642→                downloadTime = System.currentTimeMillis(),
   643→                displayName = finalName
   644→            )
   645→        )
   646→        PdfParser.parseAndSync(this@WebViewActivity, db, newDocId)
   647→        return true
   648→    }
   649→
   650→    override fun onDestroy() {
   651→        scope.cancel()
   652→        webView.destroy()
   653→        super.onDestroy()
   654→    }
   655→}
