package com.shanfuchun.courtassistant.ui

import android.annotation.SuppressLint
import android.os.Bundle
import android.util.Log
import android.view.View
import android.view.ViewGroup
import android.webkit.*
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.FileProvider
import com.shanfuchun.courtassistant.App
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.service.PdfParser
import kotlinx.coroutines.*
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONArray
import java.io.File
import java.util.concurrent.TimeUnit

/**
 * WebView Activity - 在WebView内显示PDF卡片列表
 * 用户点击卡片下载PDF文档
 */
class WebViewActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private lateinit var overlayContainer: ViewGroup
    private val TAG = "CourtAssistant"
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private var smsId: Long = 0
    private var autoMode = false
    private val db by lazy { (application as App).db }

    // 扫描到的PDF列表
    private val pdfList = mutableListOf<PdfItem>()
    private val downloadedUrls = mutableSetOf<String>()

    data class PdfItem(
        val url: String,
        val name: String,
        var downloaded: Boolean = false,
        var downloading: Boolean = false,
        var docId: Long = 0
    )

    private val client = OkHttpClient.Builder()
        .followRedirects(true)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .build()

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_webview)

        webView = findViewById<WebView>(R.id.webView)
        smsId = intent.getLongExtra("smsId", 0)
        autoMode = intent.getBooleanExtra("autoMode", false)
        val url = intent.getStringExtra("url") ?: run { finish(); return }

        Log.d(TAG, "WebView: loading url=$url smsId=$smsId autoMode=$autoMode")
        if (!autoMode) {
            Toast.makeText(this, "正在扫描文档...", Toast.LENGTH_SHORT).show()
        }

        setupWebView()
        webView.loadUrl(url)

        // 超时保底
        scope.launch {
            delay(60000)
            finishScanning()
        }
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            allowFileAccess = true
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
            userAgentString = "Mozilla/5.0 (Linux; Android 12) AppleWebKit/537.36 Chrome/120.0 Mobile Safari/537.36"
        }

        webView.addJavascriptInterface(PdfJsBridge(), "PdfBridge")

        // 拦截PDF下载
        webView.setDownloadListener { downloadUrl, _, _, _, _ ->
            Log.d(TAG, "PDF download listener: $downloadUrl")
            handlePdfDownload(downloadUrl)
        }

        webView.webViewClient = object : WebViewClient() {
            override fun onPageFinished(view: WebView, url: String) {
                Log.d(TAG, "Page loaded: $url")

                // 多次扫描以捕获动态加载的内容
                val scanTimes = listOf(2000, 4000, 6000, 10000, 15000)
                scanTimes.forEach { delay ->
                    view.postDelayed({ scanForPdfs(view) }, delay.toLong())
                }

                // 最终扫描完成
                view.postDelayed({
                    showPdfCardsOverlay()
                }, 20000)
            }
        }
    }

    private fun scanForPdfs(view: WebView) {
        val js = """
            (function() {
                var results = [];
                var seen = new Set();

                // 法院文书关键词
                var keywords = ['传票', '通知书', '举证', '受理', '判决', '裁定',
                                '送达', '应诉', '起诉', '答辩', '告知', '决定',
                                '文书', '下载', '查看', '打印', '案件'];

                // 辅助函数：添加结果（去重）
                function addResult(url, name) {
                    if (!url || url === '#' || url === 'javascript:;' ||
                        url === 'javascript:void(0)' || url.length < 10) return;

                    // 标准化URL
                    var cleanUrl = url.split('#')[0].split('?')[0];
                    if (!seen.has(cleanUrl)) {
                        seen.add(cleanUrl);
                        results.push({url: url, name: name || cleanUrl});
                    }
                }

                // 扫描所有链接和可点击元素
                var selectors = [
                    'a[href]',
                    'a[onclick]',
                    '[class*="file"]',
                    '[class*="doc"]',
                    '[class*="document"]',
                    '[class*="item"]',
                    '[class*="card"]',
                    '[onclick]',
                    '[data-href]',
                    '[data-url]',
                    'button',
                    '[role="button"]'
                ];

                for (var s = 0; s < selectors.length; s++) {
                    try {
                        var elements = document.querySelectorAll(selectors[s]);
                        for (var i = 0; i < elements.length; i++) {
                            var el = elements[i];
                            var href = el.href || el.getAttribute('data-href') ||
                                          el.getAttribute('data-url') ||
                                          el.getAttribute('onclick') || '';
                            var text = (el.innerText || el.textContent || '').trim();
                            var title = el.getAttribute('title') || '';
                            var className = el.className || '';

                            var lowerHref = href.toLowerCase();
                            var lowerText = text.toLowerCase();

                            // 判断是否为PDF文档
                            var isPdfLink = lowerHref.indexOf('.pdf') >= 0 ||
                                                   lowerHref.indexOf('pdf') >= 0;

                            // 检查是否包含文书关键词
                            var hasKeyword = keywords.some(function(kw) {
                                return lowerText.indexOf(kw) >= 0 || className.indexOf(kw) >= 0;
                            });

                            // 如果是PDF链接或包含文书关键词
                            if ((isPdfLink || hasKeyword) && href && href !== '#' &&
                                href !== 'javascript:;' && href !== 'javascript:void(0)') {
                                addResult(href, text || title);
                            }
                        }
                    } catch (e) {
                        console.log('Selector error:', e);
                    }
                }

                return JSON.stringify(results);
            })()
        """.trimIndent()

        view.evaluateJavascript(js) { result ->
            try {
                val json = result?.trim()?.removeSurrounding("\"")
                    ?.replace("\\\"", "\"")?.replace("\\\\", "\\")
                if (json.isNullOrBlank() || json == "null" || json == "[]") {
                    Log.d(TAG, "Scan: no PDFs found")
                    return@evaluateJavascript
                }

                val arr = JSONArray(json)
                Log.d(TAG, "Scan: found ${arr.length()} PDFs")

                // 更新PDF列表
                updatePdfList(arr)

            } catch (e: Exception) {
                Log.e(TAG, "Scan parse error", e)
            }
        }
    }

    private fun updatePdfList(arr: JSONArray) {
        // 将新扫描到的PDF添加到列表
        scope.launch(Dispatchers.IO) {
            val newPdfs = mutableListOf<PdfItem>()
            val newPdfsIds = mutableListOf<Long>()

            for (i in 0 until arr.length()) {
                val obj = arr.getJSONObject(i)
                val url = obj.getString("url")
                val name = obj.optString("name", "")

                // 检查是否已存在
                val existing = db.documentDao().findByUrlAndSms(url, smsId)
                if (existing != null) {
                    // 已存在，更新状态
                    newPdfs.add(PdfItem(
                        url = url,
                        name = name,
                        downloaded = existing.filePath.isNotEmpty(),
                        downloading = false,
                        docId = existing.id
                    ))
                    newPdfsIds.add(existing.id)
                } else {
                    // 新增，创建待下载记录
                    val doc = DocumentRecord(
                        smsId = smsId,
                        fileName = name,
                        filePath = "",
                        fileSize = 0,
                        sourceUrl = url,
                        downloadTime = System.currentTimeMillis(),
                        parseStatus = 4, // 待下载状态
                        displayName = name
                    )
                    val docId = db.documentDao().insert(doc)
                    newPdfs.add(PdfItem(
                        url = url,
                        name = name,
                        downloaded = false,
                        downloading = false,
                        docId = docId
                    ))
                    newPdfsIds.add(docId)
                }
            }

            // 更新UI显示
            withContext(Dispatchers.Main) {
                pdfList.clear()
                pdfList.addAll(newPdfs)
                updateCardsOverlay()
            }
        }
    }

    private fun showPdfCardsOverlay() {
        if (pdfList.isEmpty()) {
            Toast.makeText(this, "未发现PDF文档", Toast.LENGTH_SHORT).show()
            finishScanning()
            return
        }

        Log.d(TAG, "Showing PDF cards overlay: ${pdfList.size} items")

        // 生成HTML覆盖层
        val html = generatePdfCardsHtml()

        // 使用JavaScript注入覆盖层
        webView.evaluateJavascript("""
