   463→    private fun downloadPdf(index: Int, url: String) {
   464→        val pdf = pdfList.getOrNull(index) ?: return
   465→
   466→        // 标记为下载中
   467→        pdf.downloading = true
   468→        updateCardsOverlay()
   469→
   470→        // 触发下载
   471→        Log.d(TAG, "Manual download request: index=$index url=$url")
   472→
   473→        scope.launch(Dispatchers.IO) {
   474→            try {
   475→                val guessName = android.webkit.URLUtil.guessFileName(url, "", "application/pdf")
   476→                val file = File(filesDir, "pdfs/${System.currentTimeMillis()}_$guessName")
   477→                file.parentFile?.mkdirs()
   478→
   479→                val request = Request.Builder().url(url).build()
   480→                val response = client.newCall(request).execute()
   481→
   482→                if (!response.isSuccessful) {
   483→                    Log.e(TAG, "Download failed: HTTP ${response.code}")
   484→                    withContext(Dispatchers.Main) {
   485→                        pdf.downloading = false
   486→                        updateCardsOverlay()
   487→                        Toast.makeText(this@WebViewActivity, "下载失败", Toast.LENGTH_SHORT).show()
   488→                    }
   489→                    return@launch
   490→                }
   491→
   492→                val contentType = response.header("Content-Type", "") ?: ""
   493→                if (!contentType.contains("pdf", ignoreCase = true) &&
   494→                    !contentType.contains("octet-stream", ignoreCase = true) &&
   495→                    !url.lowercase().contains(".pdf")) {
   496→                    Log.d(TAG, "Skipping non-PDF: contentType=$contentType")
   497→                    pdf.downloading = false
   498→                    updateCardsOverlay()
   499→                    withContext(Dispatchers.Main) {
