   539→                        downloadTime = System.currentTimeMillis(),
   540→                        parseStatus = 0,
   541→                        displayName = pdf.name
   542→                    )
   543→                    val docId = db.documentDao().insert(newDoc)
   544→                    pdf.docId = docId
   545→                    PdfParser.parseAndSync(this@WebViewActivity, db, docId)
   546→                }
   547→
   548→                downloadedUrls.add(url)
