    private fun generatePdfCardsHtml(): String {
        val sb = StringBuilder()

        for (i in pdfList.indices) {
            val pdf = pdfList[i]
            val statusIcon = when {
                pdf.downloaded -> "?"
                pdf.downloading -> "?"
                else -> "?"
            }

            val statusColor = when {
                pdf.downloaded -> "#4CAF50"
                pdf.downloading -> "#FFA000"
                else -> "#2196F3"
            }

            val cardBg = when {
                pdf.downloaded -> "#E8F5E9"
                pdf.downloading -> "#FFF3E0"
                else -> "white"
            }

            sb.append("""
                <div style="
