                        color: ${if (pdf.downloaded || pdf.downloading) "#9E9E9E" else "white"};
                        border: none;
                        border-radius: 6px;
                        font-size: 14px;
                        font-weight: 500;
                        cursor: ${if (pdf.downloading) "wait" else "pointer"};
                        width: 100%;
                    ">
                        ${if (pdf.downloaded) "������" else if (pdf.downloading) "������..." else "? �������"}
                    </button>
                </div>
            """)
        }

        // ���ӵײ�������ť
        sb.append("""
            <div style="
                padding: 16px;
                background: white;
                border-radius: 8px;
                margin-top: 8px;
                box-shadow: 0 -2px 8px rgba(0,0,0,0.1);
            ">
                <button onclick="downloadAll()" style="
                    padding: 16px;
