    private fun updateCardsOverlay() {
        val html = generatePdfCardsHtml()
        webView.evaluateJavascript("""
            (function() {
                var container = document.querySelector('#pdf-cards-overlay > div[style*="max-width"]');
                if (container) {
                    container.innerHTML = `$html`;
                }
            })();
        """.trimIndent())
    }

    private fun downloadPdf(index: Int, url: String) {
        val pdf = pdfList.getOrNull(index) ?: return

        // ���Ϊ������
        pdf.downloading = true
        updateCardsOverlay()

        // ��������
        Log.d(TAG, "Manual download request: index=$index url=$url")

        scope.launch(Dispatchers.IO) {
            try {
                val guessName = android.webkit.URLUtil.guessFileName(url, "", "application/pdf")
                val file = File(filesDir, "pdfs/${System.currentTimeMillis()}_$guessName")
                file.parentFile?.mkdirs()

                val request = Request.Builder().url(url).build()
                val response = client.newCall(request).execute()

                if (!response.isSuccessful) {
                    Log.e(TAG, "Download failed: HTTP ${response.code}")
                    withContext(Dispatchers.Main) {
                        pdf.downloading = false
                        updateCardsOverlay()
                        Toast.makeText(this@WebViewActivity, "����ʧ��", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }

                val contentType = response.header("Content-Type", "") ?: ""
                if (!contentType.contains("pdf", ignoreCase = true) &&
                    !contentType.contains("octet-stream", ignoreCase = true) &&
                    !url.lowercase().contains(".pdf")) {
                    Log.d(TAG, "Skipping non-PDF: contentType=$contentType")
                    pdf.downloading = false
                    updateCardsOverlay()
                    withContext(Dispatchers.Main) {
                        Toast.makeText(this@WebViewActivity, "����PDF�ļ�", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }

                response.body?.byteStream()?.use { input ->
                    file.outputStream().use { output -> input.copyTo(output) }
                }

                if (file.length() == 0L) {
                    file.delete()
                    pdf.downloading = false
                    updateCardsOverlay()
                    withContext(Dispatchers.Main) {
                        Toast.makeText(this@WebViewActivity, "����ʧ��", Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }

                Log.d(TAG, "Downloaded: ${file.name} (${file.length()} bytes)")

                // �������ݿ�
                if (pdf.docId > 0) {
                    val doc = db.documentDao().getById(pdf.docId)
                    if (doc != null) {
                        db.documentDao().update(doc.copy(
                            filePath = file.absolutePath,
                            fileSize = file.length(),
                            parseStatus = 0, // ������
                        ))
                        PdfParser.parseAndSync(this@WebViewActivity, db, pdf.docId)
                    }
                } else {
                    val newDoc = DocumentRecord(
                        smsId = smsId,
                        fileName = guessName,
                        filePath = file.absolutePath,
                        fileSize = file.length(),
                        sourceUrl = url,
                        downloadTime = System.currentTimeMillis(),
                        parseStatus = 0,
                        displayName = pdf.name
                    )
                    val docId = db.documentDao().insert(newDoc)
                    pdf.docId = docId
                    PdfParser.parseAndSync(this@WebViewActivity, db, docId)
                }

                downloadedUrls.add(url)
                pdf.downloaded = true
                pdf.downloading = false

                withContext(Dispatchers.Main) {
                    updateCardsOverlay()
                    Toast.makeText(this@WebViewActivity, "������: ${file.name}", Toast.LENGTH_SHORT).show()
                }

            } catch (e: Exception) {
                Log.e(TAG, "Download error", e)
                pdf.downloading = false
                updateCardsOverlay()
                withContext(Dispatchers.Main) {
                    Toast.makeText(this@WebViewActivity, "����ʧ��: ${e.message}", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    private fun downloadAll() {
        val pendingPdfs = pdfList.filter { !it.downloaded }
        if (pendingPdfs.isEmpty()) {
            Toast.makeText(this, "û�д����ص��ĵ�", Toast.LENGTH_SHORT).show()
            return
        }

        Log.d(TAG, "Downloading all: ${pendingPdfs.size} PDFs")

        // ��������
        scope.launch {
            for ((index, pdf) in pendingPdfs.withIndex()) {
                delay(500) // �ӳٱ���ͬʱ����
                downloadPdf(index, pdf.url)
            }
        }
    }

    private fun finishScanning() {
        Log.d(TAG, "Scanning finished")

        if (pdfList.isEmpty()) {
            Toast.makeText(this, "δ����PDF�ĵ�", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        if (!autoMode) {
            Toast.makeText(this, "ɨ����ɣ����� ${pdfList.size} ��PDF�ĵ�", Toast.LENGTH_SHORT).show()
        }

        // ��ʾ���ǲ�
        showPdfCardsOverlay()

        // �Զ��ӳٹرգ����û���ʱ��鿴��
        scope.launch {
            delay(120000) // 2���Ӻ�
            if (!isFinishing) {
                finish()
            }
        }
    }

    inner class PdfJsBridge {
        @JavascriptInterface
        fun downloadPdf(index: Int, url: String) {
            Log.d(TAG, "JS Bridge: downloadPdf index=$index url=$url")
            // ����Kotlin�����ط���
            downloadPdf(index, url)
        }

        @JavascriptInterface
        fun downloadAll() {
            Log.d(TAG, "JS Bridge: downloadAll")
            // ����Kotlin��һ������ȫ������
            downloadAll()
        }

        @JavascriptInterface
        fun closeOverlay() {
            Log.d(TAG, "JS Bridge: closeOverlay")
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        webView.destroy()
        scope.cancel()
    }
}

